export interface IPDFReportOptions {
  title?: string;
  isOpen?: boolean | undefined;
  evaluation?: boolean | undefined;
  storyofus?: boolean | undefined;
  familyName?: string | undefined;
  familyImage?: string | undefined;
  onClose?: () => unknown | undefined;
  children?: any;
  worksheet?: boolean;
  headerFooter?: boolean;
  guidebook?: boolean;
  static?: boolean;
  reportLogo?: string;
  customHeader?: boolean;
  headerNoRight?: boolean;
  wide?: boolean;
  subTitle?: string;
  primaryOnePhoto?: string;
  primaryTwoPhoto?: string;
  householdId?:number;
  household?: Household;
  primaryOne?: Person;
  primaryTwo?: Person;
}

export interface IPDFEmbeddedProps {
  options: IPDFReportOptions;
  children?: any;
  isModal?: boolean;
}

const PDFEmbedded = ({ children, options }: IPDFEmbeddedProps) => {
  const [isModal, setIsModal] = React.useState(!isNullOrUndefined(options.isOpen));
  return (
    <>
      { isModal ?
        <Modal title={options.title ? options.title : 'Report'}
               isOpen={options.isOpen!==undefined ? options.isOpen : false}
               handleClose={options.onClose!==undefined ? options.onClose : (() => null)}
               width="md"
               hideFooter={true}>
          <PDFReportContent options={options} children={children} isModal={isModal}/>
        </Modal>
        :
        <PDFReportContent options={options} children={children} />
        }
    </>
  )
}

export default PDFEmbedded;
